package main

import (
	"fmt"
	"math"
)

func main() {
	var op rune
	var num float64

	if _, err := fmt.Scanf(" %c %f", &op, &num); err != nil {
		return
	}

	switch op {
	case 'c':
		fmt.Println(int(math.Ceil(num)))
	case 'f':
		fmt.Println(int(math.Floor(num)))
	case 'r':
		fmt.Println(int(math.Round(num)))
	}
}
